import React from 'react';
import { View, StyleSheet, Image } from 'react-native';
import Carousel from 'react-native-snap-carousel';

const Banner = () => {
  const images = [
    { id: 1, source: require('../../assets/images/slider.jpg') },
    { id: 2, source: require('../../assets/images/slider1.jpg') },
    { id: 3, source: require('../../assets/images/slider3.jpg') },
  ];

  const renderItem = ({ item }) => {
    return (
      <View style={styles.bannerSlide}>
        <Image source={item.source} style={styles.bannerImage} resizeMode="cover" />
      </View>
    );
  };

  return (
    <View style={styles.container}>
      <Carousel
        data={images}
        renderItem={renderItem}
        sliderWidth={300}
        itemWidth={300}
        loop={true}
        autoplay={true}
        autoplayInterval={5000}
        containerCustomStyle={styles.carouselContainer}
      />
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    marginVertical: 10,
    height: 200,
    alignItems: 'center',
  },
  carouselContainer: {
    flex: 1,
  },
  bannerSlide: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
  },
  bannerImage: {
    width: '100%',
    height: '100%',
  },
});

export default Banner;
